<script setup lang="ts">import{Head,Link}from'@inertiajs/vue3';import AuthenticatedLayout from '@/Layouts/AuthenticatedLayout.vue';import StatusBadge from '@/Components/UI/StatusBadge.vue';import Pagination from '@/Components/UI/Pagination.vue';interface Row{id:number;invoice_number:string;due_date:string;grand_total:string;paid_amount:string;remaining_amount:string;status:string|{value:string};customer:{name:string;company_name?:string}}interface P{data:Row[];links:{url:string|null;label:string;active:boolean}[];total:number}defineProps<{rows:P}>();const money=(v:string)=>new Intl.NumberFormat('id-ID',{style:'currency',currency:'IDR',maximumFractionDigits:0}).format(Number(v));const sv=(s:Row['status'])=>typeof s==='string'?s:s.value;const late=(d:string)=>Math.max(0,Math.floor((Date.now()-new Date(d).getTime())/86400000));</script><template><Head title="Piutang"/><AuthenticatedLayout><template #breadcrumb>Transaksi / Piutang</template><div class="mb-6"><h1 class="page-title">Piutang</h1><p class="page-subtitle">Tagihan pelanggan yang belum lunas.</p></div><section class="panel"><table class="data-table"><thead><tr><th>Pelanggan</th><th>Invoice</th><th>Jatuh Tempo</th><th>Grand Total</th><th>Terbayar</th><th>Sisa</th><th>Terlambat</th><th>Status</th></tr></thead><tbody><tr v-for="row in rows.data" :key="row.id"><td>{{row.customer.company_name||row.customer.name}}</td><td><Link :href="route('invoices.show',row.id)" class="font-semibold text-sky-600">{{row.invoice_number}}</Link></td><td>{{new Date(row.due_date).toLocaleDateString('id-ID')}}</td><td>{{money(row.grand_total)}}</td><td>{{money(row.paid_amount)}}</td><td class="font-bold text-red-600">{{money(row.remaining_amount)}}</td><td>{{late(row.due_date)}} hari</td><td><StatusBadge :status="sv(row.status)"/></td></tr></tbody></table><div class="border-t p-4"><Pagination :links="rows.links"/></div></section></AuthenticatedLayout></template>
